mapper.select:
SELECT e.id, e.number, e.name AS name, e.course_id AS courseId, c.course_name AS courseName, e.objective, e.status, e.create_time AS createTime, e.update_time AS updateTime, r.submitted_at AS submittedAt, r.score AS grade, r.evaluation_status AS evaluationStatus FROM tc_experiment e INNER JOIN tc_plan_detail pd ON pd.experiment_id = e.id INNER JOIN tc_lab_report r ON r.schedule_id = pd.id INNER JOIN tc_course c ON c.id = pd.course_id WHERE r.student_id = #{studentId} AND e.status = 1
AND r.evaluation_status = #{status}
AND pd.course_id = #{courseId}
ORDER BY r.create_time DESC

SELECT DISTINCT c.id, c.course_code AS courseCode, c.course_name AS courseName, c.course_type AS courseType, c.class_hours AS classHours, c.credit, c.teacher_id AS teacherId, t.name AS teacherName, c.status, c.create_time AS createTime, c.update_time AS updateTime FROM tc_course c LEFT JOIN tc_teacher t ON t.id = c.teacher_id WHERE c.id IN ( SELECT DISTINCT pd.course_id FROM tc_lab_report r INNER JOIN tc_plan_detail pd ON pd.id = r.schedule_id WHERE r.student_id = #{studentId} )
AND c.status = #{status}
ORDER BY c.create_time DESC
